import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import { Activity, Terminal, Zap, TrendingUp, TrendingDown } from 'lucide-react';

const LiveMarketPage = () => {
    // 1. Direct Context Access
    const { token } = useContext(AuthContext);

    // 2. State Management
    const [stocks, setStocks] = useState([
        { ticker: 'RELIANCE.NS', price: 2985.40, change: 0.45 },
        { ticker: 'TCS.NS', price: 4120.15, change: -0.12 },
        { ticker: 'HDFCBANK.NS', price: 1645.90, change: 0.88 },
        { ticker: 'INFY.NS', price: 1712.30, change: -0.54 }
    ]);
    const [logs, setLogs] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        if (!token) return;

        // 3. WebSocket Initialization
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);

        ws.onopen = () => {
            setIsConnected(true);
            addLog("TERMINAL_LINK_ESTABLISHED: NODE_PUNE_01");
        };

        ws.onmessage = (event) => {
            const data = JSON.parse(event.data);
            addLog(`PULSE_SYNC: STATUS=${data.status} NODE=${data.node}`);
            
            // 4. Simulate Live Price Volatility on Every Pulse
            setStocks(currentStocks => 
                currentStocks.map(s => {
                    const movement = (Math.random() - 0.5) * 5;
                    return {
                        ...s,
                        price: parseFloat((s.price + movement).toFixed(2)),
                        change: parseFloat((movement).toFixed(2))
                    };
                })
            );
        };

        ws.onclose = () => {
            setIsConnected(false);
            addLog("CONNECTION_LOST: RECONNECTING_IN_5S...");
        };

        return () => ws.close();
    }, [token]);

    const addLog = (msg) => {
        const time = new Date().toLocaleTimeString();
        setLogs(prev => [`[${time}] ${msg}`, ...prev].slice(0, 8));
    };

    return (
        <div className="reveal-node" style={containerStyle}>
            {/* Header Section */}
            <div style={headerStyle}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <Activity size={24} color={isConnected ? "var(--accent-primary)" : "#ef4444"} />
                    <h1 style={{ margin: 0, fontSize: '1.4rem', fontWeight: 800 }}>LIVE_MARKET_PULSE</h1>
                </div>
                <div style={statusTag(isConnected)}>
                    {isConnected ? 'STABLE_CONNECTION' : 'LINK_OFFLINE'}
                </div>
            </div>

            {/* Market Ticker Grid */}
            <div style={gridStyle}>
                {stocks.map((stock, i) => (
                    <div key={i} style={stockCardStyle(stock.change > 0)}>
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <span style={tickerName}>{stock.ticker}</span>
                            {stock.change > 0 ? <TrendingUp size={16} color="#10b981"/> : <TrendingDown size={16} color="#ef4444"/>}
                        </div>
                        <div style={priceStyle}>₹{stock.price}</div>
                        <div style={changeStyle(stock.change > 0)}>
                            {stock.change > 0 ? '+' : ''}{stock.change}%
                        </div>
                    </div>
                ))}
            </div>

            {/* Terminal Feed */}
            <div style={terminalContainer}>
                <div style={terminalHeader}>
                    <Terminal size={14} /> SYSTEM_EXECUTION_LOG
                </div>
                <div style={logBox}>
                    {logs.map((log, i) => (
                        <div key={i} style={logLine(i)}>{log}</div>
                    ))}
                    {logs.length === 0 && <div style={{ color: 'var(--text-muted)' }}>AWAITING_UPLINK...</div>}
                </div>
            </div>
        </div>
    );
};

/* --- Terminal UI Styles --- */
const containerStyle = { padding: '2rem', maxWidth: '1200px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '2rem' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', borderBottom: '1px solid var(--surface-border)', paddingBottom: '1rem' };
const statusTag = (online) => ({
    padding: '4px 12px', borderRadius: '4px', fontSize: '0.6rem', fontWeight: 800, fontFamily: 'monospace',
    background: online ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)',
    color: online ? 'var(--accent-primary)' : '#ef4444', border: `1px solid ${online ? 'var(--accent-primary)' : '#ef4444'}`
});
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '1.5rem' };
const stockCardStyle = (up) => ({
    padding: '1.5rem', background: 'var(--surface-glass)', border: `1px solid ${up ? 'rgba(16,185,129,0.3)' : 'rgba(239,68,68,0.3)'}`,
    borderRadius: '16px', boxShadow: up ? '0 0 15px rgba(16,185,129,0.05)' : '0 0 15px rgba(239,68,68,0.05)', transition: 'all 0.3s ease'
});
const tickerName = { fontSize: '0.7rem', color: 'var(--text-muted)', fontWeight: 700, letterSpacing: '0.1em' };
const priceStyle = { fontSize: '1.8rem', fontWeight: 900, margin: '0.5rem 0', color: 'var(--text-primary)', fontFamily: 'monospace' };
const changeStyle = (up) => ({ fontSize: '0.8rem', fontWeight: 700, color: up ? '#10b981' : '#ef4444' });
const terminalContainer = { background: '#0a0b0e', borderRadius: '12px', border: '1px solid var(--surface-border)', overflow: 'hidden' };
const terminalHeader = { padding: '0.6rem 1rem', background: '#161b22', borderBottom: '1px solid var(--surface-border)', fontSize: '0.6rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '8px' };
const logBox = { padding: '1rem', height: '180px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '6px' };
const logLine = (index) => ({
    fontSize: '0.75rem', fontFamily: 'monospace', color: index === 0 ? 'var(--accent-primary)' : 'var(--text-secondary)',
    opacity: index === 0 ? 1 : 0.5, borderLeft: index === 0 ? '2px solid var(--accent-primary)' : 'none', paddingLeft: '8px'
});

export default LiveMarketPage;
